import{_ as a,o,c as d,ak as c}from"./chunks/framework.Bhye3ZK3.js";const b=JSON.parse('{"title":"查询与工具箱","description":"","frontmatter":{},"headers":[],"relativePath":"help/sakura/tools.md","filePath":"doc/help/sakura/tools.md"}'),p={name:"help/sakura/tools.md"};function r(h,e,l,i,s,n){return o(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="查询与工具箱" tabindex="-1">查询与工具箱 <a class="header-anchor" href="#查询与工具箱" aria-label="Permalink to “查询与工具箱”">​</a></h1><div class="info custom-block github-alert"><p class="custom-block-title">使用说明</p><p>以下功能<strong>无需上传数据</strong>，绑定游戏 ID 后即可使用。</p></div><h2 id="活动与排名" tabindex="-1">活动与排名 <a class="header-anchor" href="#活动与排名" aria-label="Permalink to “活动与排名”">​</a></h2><h3 id="活动查询" tabindex="-1">活动查询 <a class="header-anchor" href="#活动查询" aria-label="Permalink to “活动查询”">​</a></h3><p><code>sk</code> / <code>分数线</code> / <code>sk线</code></p><p>查询活动排名或指定档线分数。WL 活动支持加角色名查单榜。</p><h3 id="档线时速" tabindex="-1">档线时速 <a class="header-anchor" href="#档线时速" aria-label="Permalink to “档线时速”">​</a></h3><p><code>ss</code></p><p>计算当前档线时速（20 分钟速度 × 3）。</p><p><code>wlss</code></p><p>计算角色单榜档线时速（日服限定）。</p><h3 id="查房" tabindex="-1">查房 <a class="header-anchor" href="#查房" aria-label="Permalink to “查房”">​</a></h3><p><code>查房</code></p><p>查看本人或目标档线最近 1 小时活动情况。</p><h3 id="活动信息" tabindex="-1">活动信息 <a class="header-anchor" href="#活动信息" aria-label="Permalink to “活动信息”">​</a></h3><p><code>活动 [编号]</code></p><p>查看当前活动信息，加编号查历史（如：<code>活动 86</code>）。</p><p><code>findevent [参数]</code></p><p>高级活动查询，<code>findevent help</code> 查看用法。</p><h3 id="_5v5-活动" tabindex="-1">5v5 活动 <a class="header-anchor" href="#_5v5-活动" aria-label="Permalink to “5v5 活动”">​</a></h3><p><code>5v5 胜率</code> / <code>5v5 分数</code></p><p>查询 5v5 活动双方胜率及结算分数。</p><p><code>tf启动</code></p><p>5v5 活动中赠送无偿火（功能维护中）。</p><h2 id="歌曲与谱面" tabindex="-1">歌曲与谱面 <a class="header-anchor" href="#歌曲与谱面" aria-label="Permalink to “歌曲与谱面”">​</a></h2><h3 id="歌曲信息" tabindex="-1">歌曲信息 <a class="header-anchor" href="#歌曲信息" aria-label="Permalink to “歌曲信息”">​</a></h3><p><code>pinfo [歌曲名]</code></p><p>查询歌曲信息，支持花名。</p><p><strong>花名管理：</strong></p><p><code>pset 新昵称 to 旧昵称</code> — 设置花名</p><p><code>pdel 昵称</code> — 删除花名</p><h3 id="难度排行" tabindex="-1">难度排行 <a class="header-anchor" href="#难度排行" aria-label="Permalink to “难度排行”">​</a></h3><p><code>难度排行 [数量] [属性]</code></p><p>支持 <code>fc</code>/<code>ap</code> 前缀。</p><p><strong>示例：</strong></p><p><code>难度排行 10 紫</code></p><p><code>fc难度排行 10 紫</code></p><p><code>ap难度排行 10 紫</code></p><h3 id="谱面预览" tabindex="-1">谱面预览 <a class="header-anchor" href="#谱面预览" aria-label="Permalink to “谱面预览”">​</a></h3><p><code>[歌曲名] 谱面预览</code></p><p>默认 Master，支持 <code>ex</code>/<code>apd</code> 后缀。</p><p><strong>示例：</strong></p><p><code>独りんぼエンヴィー 谱面预览</code></p><p><code>独りんぼエンヴィー 谱面预览ex</code></p><p><code>独りんぼエンヴィー 谱面预览apd</code></p><h3 id="技能预览" tabindex="-1">技能预览 <a class="header-anchor" href="#技能预览" aria-label="Permalink to “技能预览”">​</a></h3><p><code>[歌曲名] 技能预览</code></p><p>查看谱面技能分布，支持 <code>ex</code>/<code>apd</code> 后缀。</p><h3 id="歌曲搜索" tabindex="-1">歌曲搜索 <a class="header-anchor" href="#歌曲搜索" aria-label="Permalink to “歌曲搜索”">​</a></h3><p><code>查bpm [最小值] [最大值]</code></p><p><code>查物量 [数量]</code></p><p><code>随个 [组合] [level]</code></p><p><code>葱什么</code></p><h2 id="卡牌查询" tabindex="-1">卡牌查询 <a class="header-anchor" href="#卡牌查询" aria-label="Permalink to “卡牌查询”">​</a></h2><h3 id="卡牌搜索" tabindex="-1">卡牌搜索 <a class="header-anchor" href="#卡牌搜索" aria-label="Permalink to “卡牌搜索”">​</a></h3><p><code>findcard [参数]</code> / <code>查卡 [参数]</code></p><p>多条件筛选卡牌，最多 3 个参数（队名/角色/稀有度/属性）。</p><p><strong>示例：</strong></p><p><code>findcard ln 4星 粉</code></p><p><code>查卡 奏 4星</code></p><h3 id="卡面查看" tabindex="-1">卡面查看 <a class="header-anchor" href="#卡面查看" aria-label="Permalink to “卡面查看”">​</a></h3><p><code>card [编号]</code></p><p>查看卡面图。</p><p><code>cardinfo [编号]</code></p><p>查看卡牌基础信息。</p><p><code>看 [角色名]</code></p><p>随机返回该角色卡图。</p><h2 id="小游戏" tabindex="-1">小游戏 <a class="header-anchor" href="#小游戏" aria-label="Permalink to “小游戏”">​</a></h2><h3 id="pjsk-听歌识曲" tabindex="-1">PJSK 听歌识曲 <a class="header-anchor" href="#pjsk-听歌识曲" aria-label="Permalink to “PJSK 听歌识曲”">​</a></h3><p><code>pjsk听歌识曲</code></p><p>随机播放片段，40 秒内回答。</p><p><code>结束猜曲</code></p><p>中断当前游戏。</p><h3 id="pjsk-猜卡面" tabindex="-1">PJSK 猜卡面 <a class="header-anchor" href="#pjsk-猜卡面" aria-label="Permalink to “PJSK 猜卡面”">​</a></h3><p><code>pjsk猜卡面</code></p><p>随机截取卡面局部，40 秒内回答。</p><p><code>结束猜卡面</code></p><p>中断当前游戏。</p><h3 id="pjsk-抽卡" tabindex="-1">PJSK 抽卡 <a class="header-anchor" href="#pjsk-抽卡" aria-label="Permalink to “PJSK 抽卡”">​</a></h3><p><code>pjsk抽卡</code> — 默认 10 连图片</p><p><code>pjskXX连</code> — 文字结果（如：<code>pjsk100连</code>）</p><p><code>pjsk反抽卡</code> — 反转概率，需指定卡池</p><h3 id="pjsk-表情制作" tabindex="-1">PJSK 表情制作 <a class="header-anchor" href="#pjsk-表情制作" aria-label="Permalink to “PJSK 表情制作”">​</a></h3><p><code>pjsk -h</code></p><p>查看详细说明。</p><h2 id="其他工具" tabindex="-1">其他工具 <a class="header-anchor" href="#其他工具" aria-label="Permalink to “其他工具”">​</a></h2><h3 id="角色信息" tabindex="-1">角色信息 <a class="header-anchor" href="#角色信息" aria-label="Permalink to “角色信息”">​</a></h3><p><code>charinfo</code></p><p>查询角色所有花名。</p><p><code>charset [昵称] [角色]</code></p><p><code>chardel [昵称]</code></p><p>修改角色花名。</p><h3 id="自动推送" tabindex="-1">自动推送 <a class="header-anchor" href="#自动推送" aria-label="Permalink to “自动推送”">​</a></h3><blockquote><p>每日 <strong>10:00</strong> 自动检测更新并推送至订阅群，活动期间推送结活 Live 通知。</p></blockquote>',94)])])}const k=a(p,[["render",r]]);export{b as __pageData,k as default};
